#!/usr/bin/env Rscript

# 02_genomescope2.R
# Run GenomeScope 2.0 on a k-mer histogram generated by Jellyfish.
#
# Usage:
#   bin/02_genomescope2.R config/example_paths.yaml
#
# Expects:
#   - OUTDIR/kmer/reads.histo from 01_kmer_jellyfish.sh
#   - genomescope2.0 package installed and genomescope2::genomescope2()
#     available in this R library path.

suppressPackageStartupMessages({
  library(yaml)
  library(genomescope2)  # after installing genomescope2.0[web:3]
})

args <- commandArgs(trailingOnly = TRUE)
if (length(args) != 1) {
  stop("Usage: 02_genomescope2.R <config.yaml>\n", call. = FALSE)
}
config_file <- args[1]

if (!file.exists(config_file)) {
  stop(paste("Config file not found:", config_file), call. = FALSE)
}

cfg <- yaml::read_yaml(config_file)

outdir   <- cfg$outdir
kmer_dir <- file.path(outdir, "kmer")
hist_file <- file.path(kmer_dir, "reads.histo")

if (!file.exists(hist_file)) {
  stop(paste("Histogram file not found:", hist_file,
             "Run 01_kmer_jellyfish.sh first."), call. = FALSE)
}

kmer_size <- cfg$genomescope$kmer_size
ploidy    <- cfg$genomescope$ploidy

gs_outdir <- file.path(kmer_dir, "genomescope2")
dir.create(gs_outdir, showWarnings = FALSE, recursive = TRUE)

message("Running GenomeScope 2.0")
message("  Histogram: ", hist_file)
message("  k-mer size: ", kmer_size)
message("  Ploidy: ", ploidy)
message("  Output: ", gs_outdir)

# genomescope2::genomescope2 takes:
#   infile, kmer_length, read_length, ploidy, outdir, max_kmercov, ...
genomescope2::genomescope2(
  infile      = hist_file,
  kmer_length = as.integer(kmer_size),
  read_length = NA,            # HiFi length not strictly required for size estimate
  ploidy      = as.integer(ploidy),
  outdir      = gs_outdir
)

message("GenomeScope 2.0 finished. Results in: ", gs_outdir)
#Usage from your conda env:
#Rscript bin/02_genomescope2.R config/example_paths.yaml
